#!/bin/bash
SEEDS=(1213 622 626)
for SEED in "${SEEDS[@]}"; do
    python main.py --dataset_path "dataset/wn18rr" --kge_embedding_path "dataset/wn18rr/entity_embeddings.pt" --model_name_or_path "meta-llama/Meta-Llama-3-8B" --model_type llama --use_quant True --bf16 --output_dir "results_extract/wn18rr/llama3_seed${SEED}_margin" --num_train_epochs 10 --per_device_train_batch_size 8 --learning_rate 2e-4 --lora_r 32 --lora_alpha 32 --lora_dropout 0.1 --save_strategy steps --save_steps 200 --save_total_limit 10 --use_extract True --include_subgraph False --logging_steps 50 --report_to wandb --run_name "wn_train_seed${SEED}_margin" --seed_num $SEED --use_margin_loss True --use_wandb True --use_attention False
    python infer.py --dataset_path "dataset/wn18rr" --kge_embedding_path "dataset/wn18rr/entity_embeddings.pt" --checkpoint_dir "results_extract/wn18rr/llama3_seed${SEED}_margin/checkpoint-final" --model_name_or_path "meta-llama/Meta-Llama-3-8B" --model_type llama --num_return_sequences 1 --report_to wandb --use_extract True --include_subgraph False --run_name "wn_val_seed${SEED}_margin" --seed_num $SEED --use_margin_loss True --use_wandb True --use_attention False
    python main.py --dataset_path "dataset/fb15k237" --kge_embedding_path "dataset/fb15k237/entity_embeddings.pt" --model_name_or_path "meta-llama/Meta-Llama-3-8B" --model_type llama --use_quant True --bf16 --output_dir "results_extract/fb15k237/llama3_seed${SEED}_margin" --num_train_epochs 4 --per_device_train_batch_size 16 --gradient_accumulation_steps 1 --learning_rate 2e-4 --lora_r 32 --lora_alpha 32 --lora_dropout 0.1 --dataloader_num_workers 32 --save_strategy steps --save_steps 200 --save_total_limit 10 --use_extract True --include_subgraph False --logging_steps 10 --report_to wandb --run_name "fb_train_seed${SEED}_margin" --seed_num $SEED --use_margin_loss True --use_wandb True --use_attention False
    python infer.py --dataset_path "dataset/fb15k237" --kge_embedding_path "dataset/fb15k237/entity_embeddings.pt" --checkpoint_dir "results_extract/fb15k237/llama3_seed${SEED}_margin/checkpoint-final" --model_name_or_path "meta-llama/Meta-Llama-3-8B" --model_type llama --num_return_sequences 1 --report_to wandb --use_extract True --include_subgraph False --run_name "fb_val_seed${SEED}_margin" --seed_num $SEED --use_margin_loss True --use_wandb True --use_attention False
